    - Label "No Ambiguity"
    - Label "Flat Structure"
    - Label "Fast Navigation"
    - Label "Spatial Memory"
    - Text box: "Coordinate Thinking: This file exists AT the intersection"

    Style: Clean line art on graph paper background, educational diagram.
  `;

  // Same API call structure as Mode 1
}
```

### **MODE 3: Refinement (Multi-modal)**
```javascript
async function refineCartesianImage(
  previousImageBase64,  // The image to refine
  userPrompt,           // User's modification request
  referenceImageBase64, // Optional style reference
  structureText,
  metadata
) {
  // Build multi-modal input array
  const parts = [];

  // Add previous image
  if (previousImageBase64) {
    parts.push({
      inlineData: {
        mimeType: 'image/png',
        data: previousImageBase64.split(',')[1]
      }
    });
  }

  // Add text instruction
  parts.push({ text: `
    This is the current Cartesian Coordinate System visualization.
    User wants to modify it: "${userPrompt}"

    Please generate a new version incorporating these changes.
  `});

  // Add reference image if provided
  if (referenceImageBase64) {
    parts.push({
      inlineData: {
        mimeType: 'image/png',
        data: referenceImageBase64.split(',')[1]
      }
    });
    parts.push({ text: "Use this image as style reference." });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: [{ role: 'user', parts: parts }],
    config: {
      responseModalities: [Modality.TEXT, Modality.IMAGE],
      imageConfig: { aspectRatio: "16:9" }
    }
  });

  return extractImageFromResponse(response);
}
```

### **Response Parsing:**
```javascript
function extractImageFromResponse(response) {
  const parts = response.candidates[0].content.parts;

  let imageUrl = null;
  let text = '';

  for (const part of parts) {
    if (part.text) {
      text += part.text;
    }
    if (part.inlineData) {
      const { mimeType, data } = part.inlineData;
      imageUrl = `data:${mimeType};base64,${data}`;
    }
  }

  return { imageUrl, text };
}
```

